import{_ as a,o as e,c as r,a2 as i}from"./chunks/framework.BEgbRHOA.js";const c=JSON.parse('{"title":"Управление заказами","description":"","frontmatter":{},"headers":[],"relativePath":"guide/xcourier-manager/orders.md","filePath":"guide/xcourier-manager/orders.md","lastUpdated":1775746985000}'),l={name:"guide/xcourier-manager/orders.md"};function d(o,t,n,h,s,p){return e(),r("div",null,[...t[0]||(t[0]=[i('<h1 id="управление-заказами" tabindex="-1">Управление заказами <a class="header-anchor" href="#управление-заказами" aria-label="Permalink to &quot;Управление заказами&quot;">​</a></h1><h2 id="список-заказов" tabindex="-1">Список заказов <a class="header-anchor" href="#список-заказов" aria-label="Permalink to &quot;Список заказов&quot;">​</a></h2><p>Основной экран приложения — список активных заказов магазина. Заказы обновляются в реальном времени через Firestore listener.</p><p>Каждая карточка заказа содержит:</p><ul><li>Номер заказа</li><li>Имя и телефон клиента</li><li>Адрес доставки</li><li>Текущий статус (цветной бейдж)</li><li>Способ оплаты</li><li>Сумма заказа</li><li>Дата создания</li></ul><h2 id="архив-заказов" tabindex="-1">Архив заказов <a class="header-anchor" href="#архив-заказов" aria-label="Permalink to &quot;Архив заказов&quot;">​</a></h2><p>Через меню доступна страница «Все заказы» с полной историей, включая завершённые и отменённые.</p><h2 id="детали-заказа" tabindex="-1">Детали заказа <a class="header-anchor" href="#детали-заказа" aria-label="Permalink to &quot;Детали заказа&quot;">​</a></h2><p>На странице деталей менеджер видит:</p><ul><li>Полную информацию о заказе</li><li>Список товаров с изображениями, ценами и количеством</li><li>Контактные данные клиента</li><li>Адрес доставки и комментарий</li></ul><h2 id="смена-статуса" tabindex="-1">Смена статуса <a class="header-anchor" href="#смена-статуса" aria-label="Permalink to &quot;Смена статуса&quot;">​</a></h2><p>Менеджер может менять статус заказа через dropdown-меню:</p><table tabindex="0"><thead><tr><th>Переход</th><th>Действие</th></tr></thead><tbody><tr><td>Создан → Собирается</td><td>Начал сборку заказа</td></tr><tr><td>Собирается → Собран</td><td>Заказ собран, ждёт курьера</td></tr><tr><td>Собран → В пути</td><td>Курьер забрал заказ</td></tr><tr><td>В пути → Завершен</td><td>Заказ доставлен клиенту</td></tr><tr><td>Любой → Отменен</td><td>Отмена заказа</td></tr></tbody></table><p>При каждой смене статуса клиент получает push-уведомление.</p><h2 id="редактирование-заказа" tabindex="-1">Редактирование заказа <a class="header-anchor" href="#редактирование-заказа" aria-label="Permalink to &quot;Редактирование заказа&quot;">​</a></h2><p>Менеджер может отредактировать заказ:</p><ul><li>Изменить количество товара в заказе</li><li>Удалить товар из заказа</li><li>Добавить новый товар из каталога магазина</li></ul><p>Редактирование доступно до завершения или отмены заказа.</p>',18)])])}const _=a(l,[["render",d]]);export{c as __pageData,_ as default};
